import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

/**
 * GET /api/admin/tables
 *
 * Returns all tables ordered by number.
 * Each table includes orderCount: count of unpaid, non-cancelled orders.
 */
export async function GET() {
  try {
    const tables = await prisma.table.findMany({
      orderBy: { number: 'asc' },
      include: {
        orders: {
          where: {
            status: { notIn: ['PAID', 'CANCELLED'] },
          },
          select: { id: true },
        },
      },
    })

    const result = tables.map((t) => ({
      id: t.id,
      number: t.number,
      name: t.name,
      orderCount: t.orders.length,
    }))

    console.log(`[GET /api/admin/tables] Returning ${result.length} tables`)

    return NextResponse.json({ tables: result })
  } catch (error) {
    console.error('[GET /api/admin/tables] Failed:', error)
    return NextResponse.json(
      { error: 'Không thể tải danh sách bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * POST /api/admin/tables
 *
 * Creates a new table.
 * Auto-numbers to max(existing number) + 1.
 * Name auto-generated as "Bàn N".
 */
export async function POST(_request: NextRequest) {
  try {
    // Get the highest existing table number
    const last = await prisma.table.findFirst({
      orderBy: { number: 'desc' },
      select: { number: true },
    })

    const nextNumber = last ? last.number + 1 : 1
    const name = `Bàn ${nextNumber}`

    const table = await prisma.table.create({
      data: { number: nextNumber, name },
    })

    console.log(`[POST /api/admin/tables] Created table #${table.id}: ${table.name} (number=${table.number})`)

    return NextResponse.json(
      {
        id: table.id,
        number: table.number,
        name: table.name,
        orderCount: 0,
      },
      { status: 201 },
    )
  } catch (error) {
    console.error('[POST /api/admin/tables] Failed:', error)
    return NextResponse.json(
      { error: 'Không thể tạo bàn mới. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

type RouteContext = { params: Promise<{ id: string }> }

/**
 * GET /api/admin/tables/[id]
 *
 * Returns a single table with its unpaid order count.
 */
export async function GET(_request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)

  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID bàn không hợp lệ.' }, { status: 400 })
  }

  try {
    const table = await prisma.table.findUnique({
      where: { id },
      include: {
        orders: {
          where: { status: { notIn: ['PAID', 'CANCELLED'] } },
          select: { id: true },
        },
      },
    })

    if (!table) {
      return NextResponse.json({ error: 'Bàn không tồn tại.' }, { status: 404 })
    }

    console.log(`[GET /api/admin/tables/${id}] Table: ${table.name}, orderCount=${table.orders.length}`)

    return NextResponse.json({
      id: table.id,
      number: table.number,
      name: table.name,
      orderCount: table.orders.length,
    })
  } catch (error) {
    console.error(`[GET /api/admin/tables/${id}] Failed:`, error)
    return NextResponse.json(
      { error: 'Không thể tải thông tin bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * PUT /api/admin/tables/[id]
 *
 * Renames a table.
 * Body: { name: string }
 */
export async function PUT(request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)

  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID bàn không hợp lệ.' }, { status: 400 })
  }

  let body: Record<string, unknown>
  try {
    body = await request.json()
  } catch {
    return NextResponse.json({ error: 'Dữ liệu không hợp lệ.' }, { status: 400 })
  }

  const { name } = body

  if (!name || typeof name !== 'string' || name.trim().length === 0) {
    return NextResponse.json({ error: 'Tên bàn không được để trống.' }, { status: 400 })
  }

  const trimmedName = name.trim()
  if (trimmedName.length > 50) {
    return NextResponse.json({ error: 'Tên bàn không được quá 50 ký tự.' }, { status: 400 })
  }

  try {
    const existing = await prisma.table.findUnique({ where: { id } })
    if (!existing) {
      return NextResponse.json({ error: 'Bàn không tồn tại.' }, { status: 404 })
    }

    const table = await prisma.table.update({
      where: { id },
      data: { name: trimmedName },
    })

    console.log(`[PUT /api/admin/tables/${id}] Renamed to: ${table.name}`)

    return NextResponse.json({
      id: table.id,
      number: table.number,
      name: table.name,
      orderCount: existing.orders?.length ?? 0,
    })
  } catch (error) {
    console.error(`[PUT /api/admin/tables/${id}] Failed:`, error)
    return NextResponse.json(
      { error: 'Không thể cập nhật bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * DELETE /api/admin/tables/[id]
 *
 * Deletes a table only if it has no unpaid orders.
 * Guard: checks for orders with status NOT IN ['PAID', 'CANCELLED'].
 */
export async function DELETE(_request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)

  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID bàn không hợp lệ.' }, { status: 400 })
  }

  try {
    const table = await prisma.table.findUnique({ where: { id } })
    if (!table) {
      return NextResponse.json({ error: 'Bàn không tồn tại.' }, { status: 404 })
    }

    // Deletion guard: check for unpaid orders
    const unpaidOrder = await prisma.order.findFirst({
      where: { tableId: id, status: { notIn: ['PAID', 'CANCELLED'] } },
    })

    if (unpaidOrder) {
      console.log(`[DELETE /api/admin/tables/${id}] Guard triggered: unpaid orders exist`)
      return NextResponse.json(
        { error: 'Bàn đang có đơn chưa thanh toán, không thể xoá.' },
        { status: 409 },
      )
    }

    await prisma.table.delete({ where: { id } })

    console.log(`[DELETE /api/admin/tables/${id}] Deleted table: ${table.name}`)

    return new NextResponse(null, { status: 204 })
  } catch (error) {
    console.error(`[DELETE /api/admin/tables/${id}] Failed:`, error)
    return NextResponse.json(
      { error: 'Không thể xoá bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * GET /api/admin/qr-pdf
 *
 * Generates an A4 PDF with a 3×5 grid of QR codes — one per table.
 * Each QR encodes http://SHOP_IP:SHOP_PORT/order?table=N.
 * Protected by admin cookie auth.
 */

import { NextRequest } from "next/server";
import path from "path";
import PDFDocument from "pdfkit";
import QRCode from "qrcode";

import { checkAdminCookie } from "@/lib/auth";

// Force Node.js runtime — pdfkit uses Buffer/fs internally
export const runtime = "nodejs";

export async function GET(request: NextRequest) {
  // ── Auth gate ──────────────────────────────────────────────
  const cookieHeader = request.headers.get("cookie");
  if (!checkAdminCookie(cookieHeader)) {
    return Response.json({ error: "Unauthorized" }, { status: 401 });
  }

  // ── Env var validation ─────────────────────────────────────
  const shopIp = process.env.SHOP_IP;
  if (!shopIp) {
    return Response.json(
      { error: "SHOP_IP chưa được cấu hình" },
      { status: 400 },
    );
  }
  const shopPort = process.env.SHOP_PORT || "3000";
  const tableCount = Math.max(0, parseInt(process.env.TABLE_COUNT || "15", 10));

  if (tableCount === 0) {
    return Response.json(
      { error: "TABLE_COUNT phải lớn hơn 0" },
      { status: 400 },
    );
  }

  // ── Font validation ────────────────────────────────────────
  const fontPath = path.join(process.cwd(), "public", "fonts", "Inter.ttf");
  try {
    const fs = await import("fs");
    if (!fs.existsSync(fontPath)) {
      return Response.json(
        { error: "Font file not found" },
        { status: 500 },
      );
    }
  } catch {
    return Response.json(
      { error: "Font file not found" },
      { status: 500 },
    );
  }

  try {
    // ── Generate QR buffers ────────────────────────────────────
    const qrBuffers: Buffer[] = [];
    for (let n = 1; n <= tableCount; n++) {
      const url = `http://${shopIp}:${shopPort}/order?table=${n}`;
      const buf = await QRCode.toBuffer(url, {
        width: 300,
        errorCorrectionLevel: "M",
      });
      qrBuffers.push(buf);
    }

    // ── Build PDF ──────────────────────────────────────────────
    // A4: 595.28 × 841.89 pt, margin 40
    const doc = new PDFDocument({ size: "A4", margin: 40 });
    doc.registerFont("Vietnamese", fontPath);

    // Collect PDF chunks (cannot pipe to Response in Next.js)
    const chunks: Buffer[] = [];
    doc.on("data", (chunk: Buffer) => chunks.push(chunk));
    const pdfReady = new Promise<void>((resolve, reject) => {
      doc.on("end", resolve);
      doc.on("error", reject);
    });

    // ── Layout constants ─────────────────────────────────────
    const pageWidth = 595.28;
    const margin = 40;
    const cols = 3;
    const rows = 5;
    const perPage = cols * rows;
    const availableWidth = pageWidth - margin * 2;
    const colWidth = availableWidth / cols;
    const qrSize = 120;
    const rowHeight = 150;
    const titleHeight = 50;

    // ── Render pages ─────────────────────────────────────────
    const totalPages = Math.ceil(tableCount / perPage);

    for (let page = 0; page < totalPages; page++) {
      if (page > 0) doc.addPage();

      // Page title (only first page gets big title)
      if (page === 0) {
        doc
          .font("Vietnamese")
          .fontSize(20)
          .fillColor("#000000")
          .text("QR Code - TraSua", margin, margin, {
            align: "center",
            width: availableWidth,
          });
      }

      const startY = page === 0 ? margin + titleHeight : margin;
      const startIdx = page * perPage;
      const endIdx = Math.min(startIdx + perPage, tableCount);

      for (let i = startIdx; i < endIdx; i++) {
        const localIdx = i - startIdx;
        const col = localIdx % cols;
        const row = Math.floor(localIdx / cols);

        const cellX = margin + col * colWidth;
        const cellY = startY + row * rowHeight;

        // Center QR in column
        const qrX = cellX + (colWidth - qrSize) / 2;

        // Embed QR image
        doc.image(qrBuffers[i], qrX, cellY, {
          width: qrSize,
          height: qrSize,
        });

        // "Bàn N" label — 14pt, centered below QR
        doc
          .font("Vietnamese")
          .fontSize(14)
          .fillColor("#1a1a1a")
          .text(`Bàn ${i + 1}`, cellX, cellY + qrSize + 4, {
            width: colWidth,
            align: "center",
          });

        // "Quét để đặt món" subtitle — 10pt, lighter
        doc
          .font("Vietnamese")
          .fontSize(10)
          .fillColor("#666666")
          .text("Quét để đặt món", cellX, cellY + qrSize + 20, {
            width: colWidth,
            align: "center",
          });
      }
    }

    doc.end();
    await pdfReady;

    const pdfBuffer = Buffer.concat(chunks);

    return new Response(pdfBuffer, {
      status: 200,
      headers: {
        "Content-Type": "application/pdf",
        "Content-Disposition": 'attachment; filename="trasua-qr-codes.pdf"',
        "Cache-Control": "no-store",
      },
    });
  } catch (err) {
    console.error("[qr-pdf] PDF generation failed:", err);
    return Response.json(
      { error: "PDF generation failed" },
      { status: 500 },
    );
  }
}
